#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-07-18

# ============================================================================
# Quality Index Gate Self-Test (#2194)
# ============================================================================
# CI-verifies the regression gate logic itself against committed fixtures, so
# the gate cannot silently rot. Four cases:
#   1. pass    — fresh index matches baseline            -> exit 0
#   2. regress — one component's score drops > threshold -> exit 1
#   3. drop    — a baseline component disappears         -> exit 1
#   4. empty   — empty-state baseline is a loud no-op    -> exit 0 + NO-OP notice
#
# Deterministic, no network, no Claude API.
# ============================================================================
set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="${CLAUDE_PROJECT_DIR:-$(cd "$SCRIPT_DIR/../.." && pwd)}"
GATE="$PROJECT_ROOT/tests/evals/scripts/check-eval-regression.sh"
FIX="$SCRIPT_DIR/fixtures/quality-index"

if [[ -t 1 ]]; then
  RED='\033[0;31m'; GREEN='\033[0;32m'; NC='\033[0m'
else
  RED=''; GREEN=''; NC=''
fi

PASS=0
FAIL=0
log_pass() { echo -e "  ${GREEN}✓${NC} $1"; PASS=$((PASS + 1)); }
log_fail() { echo -e "  ${RED}✗${NC} $1"; FAIL=$((FAIL + 1)); }

TMP="$(mktemp -d)"
trap 'rm -rf "$TMP"' EXIT

echo "Quality Index Gate Self-Test (#2194)"

# Run the gate against a fixture results dir + baseline; capture rc + output.
run_gate() {
  local results="$1" baseline="$2"
  local out rc=0
  out="$(EVAL_RESULTS_DIR="$FIX/$results" \
         EVAL_BASELINE="$FIX/$baseline" \
         EVAL_INDEX_OUT="$TMP/current.json" \
         bash "$GATE" 2>&1)" || rc=$?
  GATE_OUT="$out"
  GATE_RC="$rc"
}

# Case 1: pass — matching results, exit 0
run_gate results-pass baseline.json
if [ "$GATE_RC" -eq 0 ]; then
  log_pass "pass case: matching results exit 0"
else
  log_fail "pass case: expected 0, got $GATE_RC"
  echo "$GATE_OUT" | sed 's/^/      /'
fi

# Case 2: regress — assess drops 0.8 -> 0.7 (> 0.05), exit 1
run_gate results-regress baseline.json
if [ "$GATE_RC" -eq 1 ]; then
  log_pass "regress case: score drop > threshold exit 1"
else
  log_fail "regress case: expected 1, got $GATE_RC"
  echo "$GATE_OUT" | sed 's/^/      /'
fi

# Case 3: drop — assess absent from current, exit 1
run_gate results-drop baseline.json
if [ "$GATE_RC" -eq 1 ]; then
  log_pass "drop case: disappeared component exit 1"
else
  log_fail "drop case: expected 1, got $GATE_RC"
  echo "$GATE_OUT" | sed 's/^/      /'
fi

# Case 4: empty-state — no components in baseline, loud no-op exit 0
run_gate results-pass baseline-empty.json
if [ "$GATE_RC" -eq 0 ] && grep -q "NO-OP" <<<"$GATE_OUT"; then
  log_pass "empty case: no-op exit 0 with loud NO-OP notice"
else
  log_fail "empty case: expected 0 + NO-OP notice, got $GATE_RC"
  echo "$GATE_OUT" | sed 's/^/      /'
fi

# Sub-check: threshold is env-overridable (a 0.10 drop passes at threshold 0.15)
OUT_RC=0
EVAL_RESULTS_DIR="$FIX/results-regress" EVAL_BASELINE="$FIX/baseline.json" \
  EVAL_INDEX_OUT="$TMP/current.json" EVAL_REGRESSION_THRESHOLD=0.15 \
  bash "$GATE" >/dev/null || OUT_RC=$?
if [ "$OUT_RC" -eq 0 ]; then
  log_pass "threshold override: 0.10 drop passes at threshold 0.15"
else
  log_fail "threshold override: expected 0 at threshold 0.15, got $OUT_RC"
fi

echo ""
echo -e "  Passed: ${GREEN}${PASS}${NC}  Failed: ${RED}${FAIL}${NC}"
[ "$FAIL" -eq 0 ] || exit 1
exit 0
